previewCss:
.darma-loader-darma-custom-269 {
  color: var(--loader-color, #7c3aed);
  display: inline-grid;
}
.darma-loader-darma-custom-269:before,
.darma-loader-darma-custom-269:after {
  content: "";
  grid-area: 1/1;
  height: 30px;
  aspect-ratio: 6;
  --c: #0000 64%,currentColor 66% 98%,#0000 101%;
  background:
    radial-gradient(35% 146% at 50% 159%,var(--c)) 0 0,
    radial-gradient(35% 146% at 50% -59%,var(--c)) 25% 100%;
  background-size: calc(100%/3) 50%;
  background-repeat: repeat-x;
  clip-path: inset(0 100% 0 0);
  animation: darma-loader-darma-custom-269-l10 1.5s infinite linear;
}
.darma-loader-darma-custom-269:after {
  scale: -1;
}
@keyframes darma-loader-darma-custom-269-l10{
  50% {clip-path: inset(0)}
  to {clip-path: inset(0 0 0 100%)}
}

